using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // ── CreateOrder — validation ────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("C1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("C1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    // ── CreateOrder — happy path ────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnOrderWithCorrectTotal()
    {
        var items = CreateItems(("Widget", 25.50m, 3));

        var order = _sut.CreateOrder("C1", items);

        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnOrderWithSummedTotal()
    {
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 4));

        var order = _sut.CreateOrder("C1", items);

        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
    }

    [TestMethod]
    public void CreateOrder_SetsCustomerId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _sut.CreateOrder("customer-42", items);

        Assert.AreEqual("customer-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_GeneratesNonEmptyId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _sut.CreateOrder("C1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;

        var order = _sut.CreateOrder("C1", CreateItems(("Widget", 10m, 1)));

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt:O} should be between {before:O} and {after:O}");
    }

    [TestMethod]
    public void CreateOrder_StoresItemsOnOrder()
    {
        var items = CreateItems(("Alpha", 5m, 1), ("Beta", 7m, 2));

        var order = _sut.CreateOrder("C1", items);

        Assert.HasCount(2, order.Items);
        Assert.AreEqual("Alpha", order.Items[0].ProductName);
        Assert.AreEqual("Beta", order.Items[1].ProductName);
    }

    [TestMethod]
    public void CreateOrder_TwoOrders_HaveDistinctIds()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order1 = _sut.CreateOrder("C1", items);
        var order2 = _sut.CreateOrder("C1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // ── GetOrder ────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var created = _sut.CreateOrder("C1", CreateItems(("Widget", 10m, 1)));

        var retrieved = _sut.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.CustomerId, retrieved.CustomerId);
        Assert.AreEqual(created.Total, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ── GetOrdersByCustomer ─────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("unknown-customer");

        Assert.IsNotNull(result);
        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllForCustomer()
    {
        _sut.CreateOrder("C1", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("C1", CreateItems(("B", 2m, 1)));
        _sut.CreateOrder("C2", CreateItems(("C", 3m, 1)));

        var result = _sut.GetOrdersByCustomer("C1");

        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ExcludesOtherCustomers()
    {
        _sut.CreateOrder("C1", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("C2", CreateItems(("B", 2m, 1)));

        var result = _sut.GetOrdersByCustomer("C1");

        Assert.ContainsSingle(result);
        Assert.AreEqual("C1", result[0].CustomerId);
    }

    // ── CreateOrder — data-driven total calculation ─────────────────

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_VariousItems_CalculatesCorrectTotal(
        string description, List<OrderItem> items, decimal expectedTotal)
    {
        var order = _sut.CreateOrder("C1", items);

        Assert.AreEqual(expectedTotal, order.Total, $"Failed for: {description}");
    }

    public static IEnumerable<(string description, List<OrderItem> items, decimal expectedTotal)> TotalCalculationData =>
    [
        ("Single unit", CreateItems(("X", 9.99m, 1)), 9.99m),
        ("Multiple quantity", CreateItems(("X", 5m, 10)), 50m),
        ("Mixed items", CreateItems(("X", 3m, 2), ("Y", 7m, 3)), 27m),
    ];
}

